parameters.jsonBody:
={
  "model": "llama-3.3-70b-versatile",
  "messages": [
    {
      "role": "system",
      "content": "You are an AI meeting assistant. Analyze the meeting transcript and return ONLY valid JSON in this exact format: {\"summary\":\"\",\"key_decisions\":[],\"action_items\":[{\"task\":\"\",\"assignee\":\"\",\"due_date\":\"\"}],\"follow_up_questions\":[],\"sentiment\":\"\"}. Do not return markdown. Do not return explanations. Return only JSON."
    },
    {
      "role": "user",
      "content": "Meeting Transcript: {{$json.meeting_text}}"
    }
  ],
  "temperature": 0.3
}

parameters.jsCode:
const raw = $json.choices[0].message.content;

const clean = raw
  .replace(/```json/g, "")
  .replace(/```/g, "")
  .trim();

const parsed = JSON.parse(clean);

return [
  {
    json: {
      summary: parsed.summary || "",
      key_decisions: parsed.key_decisions || [],
      action_items: parsed.action_items || [],
      follow_up_questions: parsed.follow_up_questions || [],
      sentiment: parsed.sentiment || ""
    }
  }
];

parameters.message:
